<template><div class="page"><h2>直播统计</h2><div class="grid grid-4"><div class="card" v-for="c in cards" :key="c.label"><div class="muted">{{c.label}}</div><div class="stat-num">{{c.value}}</div></div></div><div class="card" style="margin-top:16px"><div class="toolbar"><h3>直播会话</h3><el-date-picker v-model="range" type="daterange" value-format="YYYY-MM-DD" start-placeholder="开始" end-placeholder="结束" @change="loadLive"/></div><el-table :data="sessions"><el-table-column prop="id" label="ID" width="80"/><el-table-column prop="platform" label="平台"/><el-table-column prop="startTime" label="开始时间"/><el-table-column prop="endTime" label="结束时间"/></el-table></div></div></template>
<script setup>import { ref,onMounted } from 'vue';import { getStatsOverview,getLiveSessions,getLiveStats } from '../api/stats';const cards=ref([{label:'声音模型',value:0},{label:'TTS次数',value:0},{label:'脚本数量',value:0},{label:'直播场次',value:0}]),sessions=ref([]),range=ref([]);async function load(){const d=await getStatsOverview().catch(()=>({}));cards.value=[{label:'声音模型',value:d.voiceCount||0},{label:'TTS次数',value:d.ttsCount||0},{label:'脚本数量',value:d.scriptCount||0},{label:'直播场次',value:d.liveCount||0}];sessions.value=await getLiveSessions().catch(()=>[])||[]}async function loadLive(){if(!range.value?.length)return load();sessions.value=await getLiveStats({startDate:range.value[0],endDate:range.value[1]}).catch(()=>[])||[]}onMounted(load)</script>
